// mascotSmallLines returns the small ASCII mascot art lines.
//
// Returns []string which contains the small mascot art lines.
func mascotSmallLines() []string {
	star := colourDim(bannerStar)
	return []string{
		"     ▄██▄▄██▄",
		fmt.Sprintf(" %s  ▐▀▀▀▀▀▀▀▀▌  %s", star, star),
		"    │        │",
		fmt.Sprintf(" %s  │ (●)(●) │   %s", star, star),
		"    │        │",
		fmt.Sprintf(" %s  ╰────────╯  %s", star, star),
	}
}

// mascotLargeLines renders the large pixel-art mascot as ANSI-coloured
// half-block terminal lines.
//
// Returns []string which contains the rendered terminal lines.
func mascotLargeLines() []string {
	height := len(mascotPixels)
	lines := make([]string, 0, (height+1)/2)

	for y := 0; y < height; y += 2 {
		lines = append(lines, renderMascotRow(y, height))
	}

	return lines
}

// renderMascotRow renders a single pair of pixel rows into an ANSI-coloured
// half-block terminal line. Each output character represents two vertical
// pixels using the Unicode upper-half-block glyph.
//
// Takes y (int) which is the top row index of the pair.
// Takes height (int) which is the total number of pixel rows.
//
// Returns string which is the rendered terminal line with ANSI colour codes.
func renderMascotRow(y, height int) string {
	var b strings.Builder
	coloured := false

	for x := range mascotPixelWidth {
		topA := mascotPixels[y][x][rgbaAlphaIndex]
		botA := uint8(0)
		if y+1 < height {
			botA = mascotPixels[y+1][x][rgbaAlphaIndex]
		}

		coloured = renderMascotPixel(&b, y, x, topA, botA, coloured)
	}

	if coloured {
		b.WriteString(ansiReset)
	}

	return b.String()
}

// renderMascotPixel writes the ANSI escape sequence and half-block character
// for a single pixel column, handling all four alpha combinations.
//
// Takes b (*strings.Builder) which receives the rendered output.
// Takes y (int) which is the top row index.
// Takes x (int) which is the column index.
// Takes topA (uint8) which is the top pixel's alpha value.
// Takes botA (uint8) which is the bottom pixel's alpha value.
// Takes coloured (bool) which tracks whether the previous character used
// colour.
//
// Returns bool which is the updated coloured state after writing.
func renderMascotPixel(b *strings.Builder, y, x int, topA, botA uint8, coloured bool) bool {
	switch {
	case topA > 0 && botA > 0:
		_, _ = fmt.Fprintf(b, "\033[38;2;%d;%d;%dm\033[48;2;%d;%d;%dm▀",
			mascotPixels[y][x][0], mascotPixels[y][x][1], mascotPixels[y][x][2],
			mascotPixels[y+1][x][0], mascotPixels[y+1][x][1], mascotPixels[y+1][x][2],
		)
		return true
	case topA > 0:
		if coloured {
			b.WriteString(ansiReset)
		}
		_, _ = fmt.Fprintf(b, "\033[38;2;%d;%d;%dm▀",
			mascotPixels[y][x][0], mascotPixels[y][x][1], mascotPixels[y][x][2],
		)
		return true
	case botA > 0:
		if coloured {
			b.WriteString(ansiReset)
		}
		_, _ = fmt.Fprintf(b, "\033[38;2;%d;%d;%dm▄",
			mascotPixels[y+1][x][0], mascotPixels[y+1][x][1], mascotPixels[y+1][x][2],
		)
		return true
	default:
		if coloured {
			b.WriteString(ansiReset)
		}
		_ = b.WriteByte(' ')
		return false
	}
}

// combineSideBySide places left and right line slices next to each
// other with a gap. Right lines are vertically centred when the left
// side is taller.
//
// Takes leftLines ([]string) which provides the left column lines.
// Takes rightLines ([]string) which provides the right column lines.
// Takes gap (int) which specifies the number of spaces between
// columns.
//
// Returns []string which contains the merged side-by-side lines.
func combineSideBySide(leftLines, rightLines []string, gap int) []string {
	maxLeft := 0
	for _, line := range leftLines {
		if w := utf8.RuneCountInString(stripANSI(line)); w > maxLeft {
			maxLeft = w
		}
	}

	offset := 0
	if len(leftLines) > len(rightLines) {
		offset = (len(leftLines) - len(rightLines)) / 2
	}

	total := len(leftLines)
	if totalRight := offset + len(rightLines); totalRight > total {
		total = totalRight
	}

	gapString := strings.Repeat(bannerSpace, gap)
	result := make([]string, total)

	for i := range total {
		left := ""
		if i < len(leftLines) {
			left = leftLines[i]
		}

		right := ""
		if ri := i - offset; ri >= 0 && ri < len(rightLines) {
			right = rightLines[ri]
		}

		leftWidth := utf8.RuneCountInString(stripANSI(left))
		padding := strings.Repeat(bannerSpace, maxLeft-leftWidth)

		if right != "" {
			result[i] = left + padding + gapString + right
		} else {
			result[i] = left
		}
	}

	return result
}
